/**
 * Java implementation of IoT Device Classes
 * Demonstrates OOP concepts: inheritance, encapsulation, interfaces, polymorphism
 */

import java.util.ArrayList;
import java.util.List;

// Interface for all readable IoT devices
interface ReadableDevice {
 Object readData();
 boolean isConnected();
}

// Abstract base class for all IoT devices
abstract class IoTDevice {
 private String deviceId;
 private String location;
 private DeviceStatus status;

 // Enum for device status
 public enum DeviceStatus {
 ONLINE, OFFLINE, ERROR, STANDBY
 }

 // Constructor
 public IoTDevice(String deviceId, String location) {
 this.deviceId = deviceId;
 this.location = location;
 this.status = DeviceStatus.OFFLINE;
 }

 // Getter methods (Encapsulation)
 public String getDeviceId() {
 return deviceId;
 }

 public String getLocation() {
 return location;
 }

 public DeviceStatus getStatus() {
 return status;
 }

 // Protected setter for subclasses
 protected void setStatus(DeviceStatus status) {
 this.status = status;
 }

 // Common methods for all devices
 public boolean connect() {
 setStatus(DeviceStatus.ONLINE);
 System.out.println("[" + deviceId + "] Device connected at " + location);
 return true;
 }

 public boolean disconnect() {
 setStatus(DeviceStatus.OFFLINE);
 System.out.println("[" + deviceId + "] Device disconnected");
 return true;
 }

 // Abstract method - must be implemented by subclasses
 public abstract String getDeviceType();

 // Common toString method
 @Override
 public String toString() {
 return String.format("IoTDevice[id=%s, location=%s, status=%s]", 
 deviceId, location, status);
 }
}

// Concrete class: Temperature Sensor
class TemperatureSensor extends IoTDevice implements ReadableDevice {
 private double temperature;
 private String unit;
 private double thresholdHigh;
 private double thresholdLow;
 private List<Double> readingHistory;

 public TemperatureSensor(String deviceId, String location, String unit) {
 super(deviceId, location);
 this.unit = unit;
 this.temperature = 0.0;
 this.thresholdHigh = 30.0;
 this.thresholdLow = 5.0;
 this.readingHistory = new ArrayList<>();
 }

 // Setter for thresholds
 public void setThresholds(double low, double high) {
 this.thresholdLow = low;
 this.thresholdHigh = high;
 }

 // Read data from sensor (simulated)
 @Override
 public Double readData() {
 // Simulate sensor reading
 this.temperature = 15.0 + Math.random() * 20.0;
 readingHistory.add(temperature);

 // Keep last 10 readings
 if (readingHistory.size() > 10) {
 readingHistory.remove(0);
 }

 System.out.println(String.format("[%s] Temperature: %.2f°%s", 
 getDeviceId(), temperature, unit));
 return temperature;
 }

 @Override
 public boolean isConnected() {
 return getStatus() == DeviceStatus.ONLINE;
 }

 // Check for alert conditions
 public String checkAlert() {
 if (temperature > thresholdHigh) {
 return "HIGH TEMPERATURE ALERT: " + temperature + "°" + unit.charAt(0);
 } else if (temperature < thresholdLow) {
 return "LOW TEMPERATURE ALERT: " + temperature + "°" + unit.charAt(0);
 }
 return null;
 }

 // Calculate average of recent readings
 public double getAverage() {
 if (readingHistory.isEmpty()) return 0.0;
 double sum = 0.0;
 for (Double reading : readingHistory) {
 sum += reading;
 }
 return sum / readingHistory.size();
 }

 @Override
 public String getDeviceType() {
 return "TemperatureSensor";
 }
}

// Concrete class: Smart Actuator
class SmartActuator extends IoTDevice implements ReadableDevice {
 private boolean isActive;
 private int powerLevel;
 private String actuatorType;

 public SmartActuator(String deviceId, String location, String actuatorType) {
 super(deviceId, location);
 this.actuatorType = actuatorType;
 this.isActive = false;
 this.powerLevel = 0;
 }

 // Activate actuator
 public boolean activate(int power) {
 if (power < 0 || power > 100) {
 throw new IllegalArgumentException("Power must be between 0 and 100");
 }
 this.powerLevel = power;
 this.isActive = true;
 System.out.println(String.format("[%s] Activated at %d%% power", 
 getDeviceId(), power));
 return true;
 }

 // Deactivate actuator
 public boolean deactivate() {
 this.powerLevel = 0;
 this.isActive = false;
 System.out.println("[" + getDeviceId() + "] Deactivated");
 return true;
 }

 @Override
 public String readData() {
 return String.format("Active: %s, Power: %d%%, Type: %s", 
 isActive, powerLevel, actuatorType);
 }

 @Override
 public boolean isConnected() {
 return getStatus() == DeviceStatus.ONLINE;
 }

 @Override
 public String getDeviceType() {
 return "SmartActuator";
 }
}

// Main class to demonstrate the IoT system
public class IoTSystemDemo {
 public static void main(String[] args) {
 System.out.println("=== IoT Device Class Hierarchy Demo ===\n");

 // Create temperature sensor
 TemperatureSensor tempSensor = new TemperatureSensor("TEMP_001", "Living Room", "Celsius");
 tempSensor.connect();
 tempSensor.setThresholds(10.0, 28.0);

 // Read temperature multiple times
 System.out.println("\n--- Temperature Readings ---");
 for (int i = 0; i < 5; i++) {
 Double temp = tempSensor.readData();
 String alert = tempSensor.checkAlert();
 if (alert != null) {
 System.out.println(" ALERT: " + alert);
 }
 }

 System.out.println("\nAverage: " + String.format("%.2f", tempSensor.getAverage()) + "°C");

 // Create smart actuator
 System.out.println("\n--- Smart Actuator ---");
 SmartActuator fan = new SmartActuator("FAN_001", "Living Room", "Cooling Fan");
 fan.connect();
 fan.activate(75);

 // Demonstrate polymorphism
 System.out.println("\n--- Polymorphism Demo ---");
 List<ReadableDevice> devices = new ArrayList<>();
 devices.add(tempSensor);
 devices.add(fan);

 for (ReadableDevice device : devices) {
 System.out.println("Device Type: " + device.getClass().getSimpleName());
 System.out.println("Data: " + device.readData());
 System.out.println("Connected: " + device.isConnected());
 System.out.println();
 }

 // Display device info
 System.out.println("--- Device Information ---");
 System.out.println(tempSensor);
 System.out.println(fan);
 }
}
